mapper.select:
SELECT st.* from wc_store st left join
uc_supplier su on st.supplierId = su.id WHERE 1 = 1


    AND (
    st.`code` LIKE concat('%', #{query.name}, '%') OR
    su.`code` LIKE concat('%', #{query.name}, '%') OR
    su.`name` LIKE concat('%', #{query.name}, '%')
    )



    AND st.`issueDate`  >=  #{query.startDate}


    AND st.`issueDate`  <=  #{query.endDate}


ORDER BY st.createdTime DESC
